import React, { RefObject } from "react";
import { render, fireEvent } from "@testing-library/react-native";
import { ThemeProvider } from "styled-components/native";
import theme from "@semparar/design-system-app/src/styles/theme";
import MyOrdersCashbackView from "../../../src/screens/MyOrdersRewardProgram/view";
import { MyOrdersItem, MyOrdersItemPropsView } from "src/screens/MyOrdersRewardProgram/models";
import { PropsModalizeRef } from "@semparar/design-system-app/src/@types/modelize";

const mockNavigate = jest.fn();
const mockGoBack = jest.fn();
const formatDate = jest.fn();
const handleOpenFilters = jest.fn()

const expectOrders: MyOrdersItem[] =
    [
        {
            "id": "UmVzZ2F0ZTo0OGQzOWRkMC1jMWEwLTRlMzctODFhNC05ZmM4MzdhN2FhZTg=",
            "date": "2025-12-08T23:45:54.633000",
            "description": "Resgate",
            "type": "RESCUE",
            "amount": -7,
            "icon": "icon-tag"
        },
        {
            "id": "UmVzZ2F0ZTpiZGVkNGU0ZS02MDk2LTQxMGQtOTI3Mi1lNGVhMmE1ZDY3MWI=",
            "date": "2025-12-08T21:21:23.478000",
            "description": "Resgate",
            "type": "RESCUE",
            "amount": -10,
            "icon": "icon-tag"
        },
        {
            "id": "UmVzZ2F0ZTowZGYzMzlkYy0wNzBjLTQ4MzItYjRlMC00MDdhYmEwMTgyZjk=",
            "date": "2025-12-04T23:17:37.612000",
            "description": "Resgate",
            "type": "RESCUE",
            "amount": -10,
            "icon": "icon-tag"
        },
        {
            "id": "UmVzZ2F0ZTpiZjNlODMyNi03MjJmLTRhNzctOGNlYy0zZjE5MmY1NGNiNGM=",
            "date": "2025-12-03T23:32:57.234000",
            "description": "Resgate",
            "type": "RESCUE",
            "amount": -10,
            "icon": "icon-tag"
        }
    ]

const props = {
    emptyImage: "image.png",
    filterGroups: [],
    filtersPeriod: [],
    isError: false,
    isLoading: false,
    modalizeRefFilters: null as unknown as RefObject<PropsModalizeRef>,
    myOrders: expectOrders,
    handleGoBack: mockGoBack,
    formatDate: formatDate,
    handleOpenFilters: handleOpenFilters
};

const SKELETON_COUNT = 3

jest.mock('@react-navigation/native', () => ({
    useNavigation: () => ({
        navigate: mockNavigate,
        goBack: mockGoBack,
    }),
    useNavigationState: jest.fn(),
}));


jest.mock('react-native', () => {
    const RN = jest.requireActual('react-native');
    return {
        ...RN,
        FlatList: props => {
            const { data = [], renderItem, ListEmptyComponent, testID } = props;

            if (!data || data.length === 0) {
                // render ListEmptyComponent
                return (
                    <RN.View testID={testID}>
                        {ListEmptyComponent && <ListEmptyComponent />}
                    </RN.View>
                );
            }

            return (
                <RN.View testID={testID}>
                    {data.map((item, index) => {
                        props.keyExtractor?.(item, index);
                        return renderItem({ item, index });
                    })}
                </RN.View>
            );
        },
    };
});


const renderComponentView = (props: MyOrdersItemPropsView) => {
    return render(
        <ThemeProvider theme={theme}>
            <MyOrdersCashbackView
                {...props}
            />
        </ThemeProvider>
    );
}



describe('MyOrdersRewardProgram Component', () => {

    it('should render InvoiceCashbackView with correct props', () => {
        expect(renderComponentView(props)).toBeTruthy;
    });

    it('should render InvoiceCashbackView with empty orders', () => {
        const { getByText, getByTestId } = renderComponentView({ ...props, myOrders: [] });

        expect(getByText('Nenhum pedido feito')).toBeTruthy();
    });

    it('should render InvoiceCashbackView loading list', () => {
        const { getByTestId, getAllByTestId } = renderComponentView({ ...props, isLoading: true });

        expect(getByTestId('loading-list-cashback')).toBeTruthy();

        expect(getAllByTestId('loading-orders-cashback').length).toBe(SKELETON_COUNT);

    });

    it('should render InvoiceCashbackView loading list', () => {
        const { getByTestId } = renderComponentView({ ...props, isError: true });

        expect(getByTestId('orders-cashback-error').props.children).toBeTruthy();
    });



})

